107→        public actual fun fromEpochSeconds(epochSeconds: Long, nanosecondAdjustment: Long): Instant = try {
108→            /* Performing normalization here because otherwise this fails:
109→               assertEquals((Long.MAX_VALUE % 1_000_000_000).toInt(),
