{"file_path": "/project/test_instant_parse_fix.kt", "content": "import kotlinx.datetime.*
import kotlinx.datetime.format.*

fun testInstantParseFix() {
    println("Testing Instant.parse() fix for consistent behavior...")

    // Test cases that SHOULD work (seconds are present)
    val validCases = listOf(
        "2024-03-19T17:50:00Z",    // With seconds
        "2024-03-19T17:50:01Z",    // With seconds
        "2024-03-19T17:50:00.123Z", // With fractional seconds
        "2024-03-19T17:50:00+01:00", // With seconds and offset
    )

    // Test cases that should FAIL (seconds are missing - not allowed by spec)
    val invalidCases = listOf(
        "2024-03-19T17:50Z",       // Missing seconds - this should now fail on all platforms
        "2024-03-19T17:50+01:00",  // Missing seconds with offset
        "2024-03-19T17:50-05:30",  // Missing seconds with negative offset
    )

    println("\n=== Testing valid cases (should parse successfully) ===")
    for (case in validCases) {
        try {
            val instant = Instant.parse(case)
            println("✓ PASS: '$case' -> $instant")
        } catch (e: DateTimeFormatException) {
            println("✗ FAIL: '$case' should be valid but threw: ${e.message}")
        }
    }

    println("\n=== Testing invalid cases (should fail to parse) ===")
    for (case in invalidCases) {
        try {
            val instant = Instant.parse(case)
            println("✗ FAIL: '$case' should be invalid but parsed to: $instant")
        } catch (e: DateTimeFormatException) {
            println("✓ PASS: '$case' correctly failed with: ${e.message}")
        }
    }

    println("\n=== Testing with explicit format ===")
    val format = DateTimeComponents.Formats.ISO_DATE_TIME_OFFSET

    for (case in invalidCases) {
        try {
            val instant = Instant.parse(case, format)
            println("✗ FAIL: '$case' with explicit format should be invalid but parsed to: $instant")
        } catch (e: DateTimeFormatException) {
            println("✓ PASS: '$case' with explicit format correctly failed")
        }
    }
}

fun main() {
    testInstantParseFix()
}"}

